            case Sound.BucketEmpty value when value.Liquid is Block.Water or Block.Lava:
                encoded = new(84u, value.Liquid is Block.Water ? 0u : 1u, 0, 0u, 0d, value.Liquid, null); return true;
            case Sound.CrossbowLoad value:
                encoded = new(85u, 0u, value.Stage, value.QuickCharge ? 1u : 0u, 0d, null, null); return true;
            case Sound.GoatHorn value:
                encoded = new(86u, value.Horn.Uint8(), 0, 0u, 0d, null, null); return true;
            default:
                encoded = default; return false;
        }
    }
}
